const TZ_OFFSET_HOURS = 8; // Adjust if needed

const shiftToTz = (date, offsetHours) =>
  new Date(date.getTime() + offsetHours * 3600 * 1000);

const formatLocal = (d) =>
  `${d.getUTCFullYear()}-${String(d.getUTCMonth() + 1).padStart(2, '0')}-${String(d.getUTCDate()).padStart(2, '0')}`;

const nowUtc = new Date();
const todayLocal = shiftToTz(nowUtc, TZ_OFFSET_HOURS);

const sevenDaysAgoLocal = new Date(
  todayLocal.getTime() - (7 * 24 * 60 * 60 * 1000)
);

return [
  {
    json: {
      date_one_week_ago: formatLocal(sevenDaysAgoLocal),
    }
  }
];

